			{
				using AWSHttpClient httpClient = GetHttpClient(config);
				foreach (Tuple<string, IEnumerable<string>, HttpStatusCode> item in await httpClient.GetResponseHeadersAsync("Head", url))
				{
					if (!string.Equals(item.Item1, "x-amz-bucket-region", StringComparison.OrdinalIgnoreCase))
					{
						continue;
					}
					using IEnumerator<string> enumerator2 = item.Item2.GetEnumerator();
					if (enumerator2.MoveNext())
					{
						string current2 = enumerator2.Current;
						return new GetHeadResponse
