	internal class AbortMultipartUploadsCommand : BaseCommand
	{
		private IAmazonS3 _s3Client;

		private string _bucketName;

		private DateTime _initiatedDate;

		private TransferUtilityConfig _config;

		internal AbortMultipartUploadsCommand(IAmazonS3 s3Client, string bucketName, DateTime initiateDate)
		{
			_s3Client = s3Client;
			_bucketName = bucketName;
			_initiatedDate = initiateDate;
		}

		private ListMultipartUploadsRequest ConstructListMultipartUploadsRequest(ListMultipartUploadsResponse listResponse)
		{
			ListMultipartUploadsRequest listMultipartUploadsRequest = new ListMultipartUploadsRequest();
			listMultipartUploadsRequest.BucketName = _bucketName;
			listMultipartUploadsRequest.KeyMarker = listResponse.KeyMarker;
			listMultipartUploadsRequest.UploadIdMarker = listResponse.NextUploadIdMarker;
			((IAmazonWebServiceRequest)listMultipartUploadsRequest).AddBeforeRequestHandler((RequestEventHandler)base.RequestEventHandler);
			return listMultipartUploadsRequest;
		}

		private AbortMultipartUploadRequest ConstructAbortMultipartUploadRequest(MultipartUpload upload)
		{
			AbortMultipartUploadRequest abortMultipartUploadRequest = new AbortMultipartUploadRequest();
			abortMultipartUploadRequest.BucketName = _bucketName;
			abortMultipartUploadRequest.Key = upload.Key;
			abortMultipartUploadRequest.UploadId = upload.UploadId;
			((IAmazonWebServiceRequest)abortMultipartUploadRequest).AddBeforeRequestHandler((RequestEventHandler)base.RequestEventHandler);
			return abortMultipartUploadRequest;
		}

		internal AbortMultipartUploadsCommand(IAmazonS3 s3Client, string bucketName, DateTime initiateDate, TransferUtilityConfig config)
		{
			_s3Client = s3Client;
			_bucketName = bucketName;
			_initiatedDate = initiateDate;
			_config = config;
		}

		public override async Task ExecuteAsync(CancellationToken cancellationToken)
		{
			if (string.IsNullOrEmpty(_bucketName))
			{
				throw new InvalidOperationException("The bucketName specified is null or empty!");
			}
			SemaphoreSlim asyncThrottler = null;
			CancellationTokenSource internalCts = null;
			try
			{
				asyncThrottler = new SemaphoreSlim(_config.ConcurrentServiceRequests);
				internalCts = new CancellationTokenSource();
				CancellationToken internalCancellationToken = internalCts.Token;
				ListMultipartUploadsResponse listResponse = new ListMultipartUploadsResponse();
				List<Task<AbortMultipartUploadResponse>> pendingTasks = new List<Task<AbortMultipartUploadResponse>>();
				do
				{
					ListMultipartUploadsRequest request = ConstructListMultipartUploadsRequest(listResponse);
					listResponse = await _s3Client.ListMultipartUploadsAsync(request, cancellationToken).ConfigureAwait(continueOnCapturedContext: false);
					foreach (MultipartUpload upload in listResponse.MultipartUploads)
					{
						cancellationToken.ThrowIfCancellationRequested();
						if (!internalCancellationToken.IsCancellationRequested)
						{
							if (upload.Initiated < _initiatedDate)
							{
								await asyncThrottler.WaitAsync(cancellationToken).ConfigureAwait(continueOnCapturedContext: false);
								AbortMultipartUploadRequest abortRequest = ConstructAbortMultipartUploadRequest(upload);
								Task<AbortMultipartUploadResponse> item = AbortAsync(abortRequest, internalCts, cancellationToken, asyncThrottler);
								pendingTasks.Add(item);
							}
							continue;
						}
						break;
					}
				}
				while (listResponse.IsTruncated);
				await BaseCommand.WhenAllOrFirstExceptionAsync(pendingTasks, cancellationToken).ConfigureAwait(continueOnCapturedContext: false);
			}
			finally
			{
				internalCts?.Dispose();
				asyncThrottler?.Dispose();
			}
		}

		private async Task<AbortMultipartUploadResponse> AbortAsync(AbortMultipartUploadRequest abortRequest, CancellationTokenSource internalCts, CancellationToken cancellationToken, SemaphoreSlim asyncThrottler)
		{
			try
			{
				return await _s3Client.AbortMultipartUploadAsync(abortRequest, cancellationToken).ConfigureAwait(continueOnCapturedContext: false);
			}
			catch (Exception ex)
			{
				if (!(ex is OperationCanceledException))
				{
					internalCts.Cancel();
				}
				throw;
			}
			finally
			{
				asyncThrottler.Release();
			}
		}
	}
	internal abstract class BaseCommand
	{
		public virtual object Return => null;

		protected GetObjectRequest ConvertToGetObjectRequest(BaseDownloadRequest request)
		{
			GetObjectRequest getObjectRequest = new GetObjectRequest
			{
				BucketName = request.BucketName,
				Key = request.Key,
				VersionId = request.VersionId
			};
			((IAmazonWebServiceRequest)getObjectRequest).AddBeforeRequestHandler((RequestEventHandler)RequestEventHandler);
			if (request.IsSetModifiedSinceDateUtc())
			{
				getObjectRequest.ModifiedSinceDateUtc = request.ModifiedSinceDateUtc;
			}
			if (request.IsSetUnmodifiedSinceDateUtc())
			{
				getObjectRequest.UnmodifiedSinceDateUtc = request.UnmodifiedSinceDateUtc;
			}
			getObjectRequest.ServerSideEncryptionCustomerMethod = request.ServerSideEncryptionCustomerMethod;
			getObjectRequest.ServerSideEncryptionCustomerProvidedKey = request.ServerSideEncryptionCustomerProvidedKey;
			getObjectRequest.ServerSideEncryptionCustomerProvidedKeyMD5 = request.ServerSideEncryptionCustomerProvidedKeyMD5;
			return getObjectRequest;
		}

		protected void RequestEventHandler(object sender, RequestEventArgs args)
		{
			if (args is WebServiceRequestEventArgs e)
			{
				string text = e.Headers["User-Agent"];
				e.Headers["User-Agent"] = text + " TransferManager/" + GetType().Name;
			}
		}

		public abstract Task ExecuteAsync(CancellationToken cancellationToken);

		protected static async Task<List<T>> WhenAllOrFirstExceptionAsync<T>(List<Task<T>> pendingTasks, CancellationToken cancellationToken)
		{
			int processed = 0;
			int total = pendingTasks.Count;
			List<T> responses = new List<T>();
			for (; processed < total; processed = checked(processed + 1))
			{
				cancellationToken.ThrowIfCancellationRequested();
				Task<T> completedTask = await Task.WhenAny(pendingTasks).ConfigureAwait(continueOnCapturedContext: false);
				responses.Add(await completedTask.ConfigureAwait(continueOnCapturedContext: false));
				pendingTasks.Remove(completedTask);
			}
			return responses;
		}

		protected static async Task WhenAllOrFirstExceptionAsync(List<Task> pendingTasks, CancellationToken cancellationToken)
		{
			int processed = 0;
			for (int total = pendingTasks.Count; processed < total; processed = checked(processed + 1))
			{
				cancellationToken.ThrowIfCancellationRequested();
				Task completedTask = await Task.WhenAny(pendingTasks).ConfigureAwait(continueOnCapturedContext: false);
				await completedTask.ConfigureAwait(continueOnCapturedContext: false);
				pendingTasks.Remove(completedTask);
			}
		}

		protected static async Task ExecuteCommandAsync(BaseCommand command, CancellationTokenSource internalCts, SemaphoreSlim throttler)
		{
			try
			{
				await command.ExecuteAsync(internalCts.Token).ConfigureAwait(continueOnCapturedContext: false);
			}
			catch (Exception ex)
			{
				if (!(ex is OperationCanceledException))
				{
					internalCts.Cancel();
				}
				throw;
			}
			finally
			{
				throttler.Release();
			}
		}
	}
	internal class DownloadCommand : BaseCommand
	{
		private static int MAX_BACKOFF_IN_MILLISECONDS = checked((int)TimeSpan.FromSeconds(30.0).TotalMilliseconds);

		private static ICollection<WebExceptionStatus> WebExceptionStatusesToRetryOn = new HashSet<WebExceptionStatus>
		{
			WebExceptionStatus.ConnectFailure,
			WebExceptionStatus.ConnectionClosed,
			WebExceptionStatus.KeepAliveFailure,
			WebExceptionStatus.NameResolutionFailure,
			WebExceptionStatus.ReceiveFailure
		};

		private IAmazonS3 _s3Client;

		private TransferUtilityDownloadRequest _request;

		private static Logger Logger => Logger.GetLogger(typeof(TransferUtility));

		internal DownloadCommand(IAmazonS3 s3Client, TransferUtilityDownloadRequest request)
		{
			_s3Client = s3Client;
			_request = request;
		}

		private void ValidateRequest()
		{
			if (!_request.IsSetBucketName())
			{
				throw new InvalidOperationException("The BucketName specified is null or empty!");
			}
			if (!_request.IsSetKey())
			{
				throw new InvalidOperationException("The Key specified is null or empty!");
			}
		}

		private void OnWriteObjectProgressEvent(object sender, WriteObjectProgressArgs e)
		{
			_request.OnRaiseProgressEvent(e);
		}

		private static bool HandleException(Exception exception, int retries, int maxRetries)
		{
			bool flag = true;
			if (exception is IOException)
			{
				if (retries < maxRetries)
				{
					Logger.InfoFormat("Encountered an IOException. Retrying, retry {0} of {1}.", retries, maxRetries);
					return true;
				}
				flag = false;
			}
			if (exception is WebException ex)
			{
				Logger.Error(exception, "Encountered a WebException ({1}).", ((object)ex).GetType().Name, ex.Status);
				if (WebExceptionStatusesToRetryOn.Contains(ex.Status) && retries < maxRetries)
				{
					Logger.InfoFormat("Encountered a WebException ({0}). Retrying, retry {1} of {2}.", ex.Status, retries, maxRetries);
					return true;
				}
				flag = false;
			}
			if (!flag)
			{
				Logger.Error(exception, "Encountered a {0}. Reached maximum retries {1} of {2}.", ((object)exception).GetType().Name, retries, maxRetries);
				return false;
			}
			Logger.Error(exception, "Encountered a non retryable {0}, rethrowing exception.", ((object)exception).GetType().Name);
			return false;
		}

		private static void WaitBeforeRetry(int retries)
		{
			AWSSDKUtils.Sleep(Math.Min(checked((int)(Math.Pow(4.0, retries) * 100.0)), MAX_BACKOFF_IN_MILLISECONDS));
		}

		public override async Task ExecuteAsync(CancellationToken cancellationToken)
		{
			ValidateRequest();
			GetObjectRequest getRequest = ConvertToGetObjectRequest(_request);
			int maxRetries = _s3Client.Config.MaxErrorRetry;
			int retries = 0;
			string mostRecentETag = null;
			bool shouldRetry;
			do
			{
				shouldRetry = false;
				if (retries != 0)
				{
					getRequest.ByteRange = await ByteRangeRemainingForDownloadAsync(_request.FilePath).ConfigureAwait(continueOnCapturedContext: false);
				}
				try
				{
					using (GetObjectResponse response = await _s3Client.GetObjectAsync(getRequest, cancellationToken).ConfigureAwait(continueOnCapturedContext: false))
					{
						if (!string.IsNullOrEmpty(mostRecentETag) && !string.Equals(mostRecentETag, response.ETag))
						{
							mostRecentETag = response.ETag;
							getRequest.ByteRange = null;
							retries = 0;
							shouldRetry = true;
							WaitBeforeRetry(retries);
							continue;
						}
						mostRecentETag = response.ETag;
						if (retries == 0)
						{
							IFile file = await FileSystem.Current.GetFileFromPathAsync(_request.FilePath).ConfigureAwait(continueOnCapturedContext: false);
							if (file != null)
							{
								await file.DeleteAsync().ConfigureAwait(continueOnCapturedContext: false);
							}
							response.WriteObjectProgressEvent += OnWriteObjectProgressEvent;
							await response.WriteResponseStreamToFileAsync(_request.FilePath, append: false, cancellationToken).ConfigureAwait(continueOnCapturedContext: false);
						}
						else
						{
							response.WriteObjectProgressEvent += OnWriteObjectProgressEvent;
							await response.WriteResponseStreamToFileAsync(_request.FilePath, append: true, cancellationToken).ConfigureAwait(continueOnCapturedContext: false);
						}
					}
					goto IL_055e;
				}
				catch (Exception ex)
				{
					retries = checked(retries + 1);
					shouldRetry = HandleExceptionForHttpClient(ex, retries, maxRetries);
					if (!shouldRetry)
					{
						if (ex is IOException)
						{
							throw;
						}
						if (!(ex.InnerException is IOException))
						{
							if (ex is AmazonServiceException || ex is AmazonClientException)
							{
								throw;
							}
							throw new AmazonServiceException(ex);
						}
						ExceptionDispatchInfo.Capture(ex.InnerException).Throw();
					}
					goto IL_055e;
				}
				IL_055e:
				WaitBeforeRetry(retries);
			}
			while (shouldRetry);
		}

		private static bool HandleExceptionForHttpClient(Exception exception, int retries, int maxRetries)
		{
			if (AWSHttpClient.IsHttpInnerException(exception))
			{
				Exception innerException = exception.InnerException;
				if (innerException is IOException || innerException is WebException)
				{
					return HandleException(innerException, retries, maxRetries);
				}
				return false;
			}
			return HandleException(exception, retries, maxRetries);
		}

		private static async Task<ByteRange> ByteRangeRemainingForDownloadAsync(string filepath)
		{
			ByteRange byteRange = new ByteRange(0L, 9223372036854775807L);
			IFile file = await FileSystem.Current.GetFileFromPathAsync(filepath).ConfigureAwait(continueOnCapturedContext: false);
			if (file != null)
			{
				using Stream stream = await file.OpenAsync(PCLStorage.FileAccess.Read).ConfigureAwait(continueOnCapturedContext: false);
				byteRange.Start = stream.Length;
			}
			return byteRange;
		}
	}
	internal class MultipartUploadCommand : BaseCommand
	{
		private IAmazonS3 _s3Client;

		private long _partSize;

		private int _totalNumberOfParts;

		private TransferUtilityConfig _config;

		private TransferUtilityUploadRequest _fileTransporterRequest;

		private List<UploadPartResponse> _uploadResponses = new List<UploadPartResponse>();

		private long _totalTransferredBytes;

		private Queue<UploadPartRequest> _partsToUpload = new Queue<UploadPartRequest>();

		private long _contentLength;

		private static Logger Logger => Logger.GetLogger(typeof(TransferUtility));

		public SemaphoreSlim AsyncThrottler { get; set; }

		internal MultipartUploadCommand(IAmazonS3 s3Client, TransferUtilityConfig config, TransferUtilityUploadRequest fileTransporterRequest)
		{
			_config = config;
			if (fileTransporterRequest.IsSetFilePath())
			{
				Logger.DebugFormat("Beginning upload of file {0}.", fileTransporterRequest.FilePath);
			}
			else
			{
				Logger.DebugFormat("Beginning upload of stream.");
			}
			_s3Client = s3Client;
			_fileTransporterRequest = fileTransporterRequest;
			_contentLength = _fileTransporterRequest.ContentLength;
			if (fileTransporterRequest.IsSetPartSize())
			{
				_partSize = fileTransporterRequest.PartSize;
			}
			else
			{
				_partSize = calculatePartSize(_contentLength);
			}
			if (fileTransporterRequest.InputStream != null && fileTransporterRequest.AutoResetStreamPosition && fileTransporterRequest.InputStream.CanSeek)
			{
				fileTransporterRequest.InputStream.Seek(0L, SeekOrigin.Begin);
			}
			Logger.DebugFormat("Upload part size {0}.", _partSize);
		}

		private static long calculatePartSize(long fileSize)
		{
			double num = Math.Ceiling((double)fileSize / 10000.0);
			if (num < (double)S3Constants.MinPartSize)
			{
				num = S3Constants.MinPartSize;
			}
			return checked((long)num);
		}

		private string determineContentType()
		{
			if (_fileTransporterRequest.IsSetContentType())
			{
				return _fileTransporterRequest.ContentType;
			}
			if (_fileTransporterRequest.IsSetFilePath() || _fileTransporterRequest.IsSetKey())
			{
				string extension = AWSSDKUtils.GetExtension(_fileTransporterRequest.FilePath);
				if (string.IsNullOrEmpty(extension) && _fileTransporterRequest.IsSetKey())
				{
					extension = AWSSDKUtils.GetExtension(_fileTransporterRequest.Key);
				}
				return AmazonS3Util.MimeTypeFromExtension(extension);
			}
			return null;
		}

		private int CalculateConcurrentServiceRequests()
		{
			int num = ((!_fileTransporterRequest.IsSetFilePath() || _s3Client is IAmazonS3Encryption) ? 1 : _config.ConcurrentServiceRequests);
			if (_totalNumberOfParts < num)
			{
				num = _totalNumberOfParts;
			}
			return num;
		}

		private CompleteMultipartUploadRequest ConstructCompleteMultipartUploadRequest(InitiateMultipartUploadResponse initResponse)
		{
			if (_uploadResponses.Count != _totalNumberOfParts)
			{
				throw new InvalidOperationException($"Cannot complete multipart upload request. The total number of completed parts ({_uploadResponses.Count}) " + $"does not equal the total number of parts created ({_totalNumberOfParts}).");
			}
			CompleteMultipartUploadRequest completeMultipartUploadRequest = new CompleteMultipartUploadRequest();
			completeMultipartUploadRequest.BucketName = _fileTransporterRequest.BucketName;
			completeMultipartUploadRequest.Key = _fileTransporterRequest.Key;
			completeMultipartUploadRequest.UploadId = initResponse.UploadId;
			completeMultipartUploadRequest.AddPartETags(_uploadResponses);
			((IAmazonWebServiceRequest)completeMultipartUploadRequest).AddBeforeRequestHandler((RequestEventHandler)base.RequestEventHandler);
			return completeMultipartUploadRequest;
		}

		private UploadPartRequest ConstructUploadPartRequest(int partNumber, long filePosition, InitiateMultipartUploadResponse initResponse)
		{
			UploadPartRequest uploadPartRequest = new UploadPartRequest
			{
				BucketName = _fileTransporterRequest.BucketName,
				Key = _fileTransporterRequest.Key,
				UploadId = initResponse.UploadId,
				PartNumber = partNumber,
				PartSize = _partSize,
				ServerSideEncryptionCustomerMethod = _fileTransporterRequest.ServerSideEncryptionCustomerMethod,
				ServerSideEncryptionCustomerProvidedKey = _fileTransporterRequest.ServerSideEncryptionCustomerProvidedKey,
				ServerSideEncryptionCustomerProvidedKeyMD5 = _fileTransporterRequest.ServerSideEncryptionCustomerProvidedKeyMD5
			};
			if (checked(filePosition + _partSize) >= _contentLength && _s3Client is IAmazonS3Encryption)
			{
				uploadPartRequest.IsLastPart = true;
				uploadPartRequest.PartSize = 0L;
			}
			ProgressHandler progressHandler = new ProgressHandler(UploadPartProgressEventCallback);
			((IAmazonWebServiceRequest)uploadPartRequest).StreamUploadProgressCallback = (EventHandler<StreamTransferProgressArgs>)Delegate.Combine(((IAmazonWebServiceRequest)uploadPartRequest).StreamUploadProgressCallback, new EventHandler<StreamTransferProgressArgs>(progressHandler.OnTransferProgress));
			((IAmazonWebServiceRequest)uploadPartRequest).AddBeforeRequestHandler((RequestEventHandler)base.RequestEventHandler);
			if (_fileTransporterRequest.IsSetFilePath())
			{
				uploadPartRequest.FilePosition = filePosition;
				uploadPartRequest.FilePath = _fileTransporterRequest.FilePath;
			}
			else
			{
				uploadPartRequest.InputStream = _fileTransporterRequest.InputStream;
			}
			if (initResponse.ServerSideEncryptionMethod == ServerSideEncryptionMethod.AWSKMS)
			{
				((IAmazonWebServiceRequest)uploadPartRequest).UseSigV4 = true;
			}
			return uploadPartRequest;
		}

		private InitiateMultipartUploadRequest ConstructInitiateMultipartUploadRequest()
		{
			InitiateMultipartUploadRequest initiateMultipartUploadRequest = new InitiateMultipartUploadRequest
			{
				BucketName = _fileTransporterRequest.BucketName,
				Key = _fileTransporterRequest.Key,
				CannedACL = _fileTransporterRequest.CannedACL,
				ContentType = determineContentType(),
				StorageClass = _fileTransporterRequest.StorageClass,
				ServerSideEncryptionMethod = _fileTransporterRequest.ServerSideEncryptionMethod,
				ServerSideEncryptionKeyManagementServiceKeyId = _fileTransporterRequest.ServerSideEncryptionKeyManagementServiceKeyId,
				ServerSideEncryptionCustomerMethod = _fileTransporterRequest.ServerSideEncryptionCustomerMethod,
				ServerSideEncryptionCustomerProvidedKey = _fileTransporterRequest.ServerSideEncryptionCustomerProvidedKey,
				ServerSideEncryptionCustomerProvidedKeyMD5 = _fileTransporterRequest.ServerSideEncryptionCustomerProvidedKeyMD5,
				TagSet = _fileTransporterRequest.TagSet
			};
			((IAmazonWebServiceRequest)initiateMultipartUploadRequest).AddBeforeRequestHandler((RequestEventHandler)base.RequestEventHandler);
			if (_fileTransporterRequest.Metadata != null && _fileTransporterRequest.Metadata.Count > 0)
			{
				initiateMultipartUploadRequest.Metadata = _fileTransporterRequest.Metadata;
			}
			if (_fileTransporterRequest.Headers != null && _fileTransporterRequest.Headers.Count > 0)
			{
				initiateMultipartUploadRequest.Headers = _fileTransporterRequest.Headers;
			}
			return initiateMultipartUploadRequest;
		}

		private void UploadPartProgressEventCallback(object sender, UploadProgressArgs e)
		{
			long transferred = Interlocked.Add(ref _totalTransferredBytes, checked(e.IncrementTransferred - e.CompensationForRetry));
			UploadProgressArgs progressArgs = new UploadProgressArgs(e.IncrementTransferred, transferred, _contentLength, e.CompensationForRetry, _fileTransporterRequest.FilePath);
			_fileTransporterRequest.OnRaiseProgressEvent(progressArgs);
		}

		public override async Task ExecuteAsync(CancellationToken cancellationToken)
		{
			InitiateMultipartUploadRequest request = ConstructInitiateMultipartUploadRequest();
			InitiateMultipartUploadResponse initResponse = await _s3Client.InitiateMultipartUploadAsync(request, cancellationToken).ConfigureAwait(continueOnCapturedContext: false);
			Logger.DebugFormat("Initiated upload: {0}", initResponse.UploadId);
			List<Task<UploadPartResponse>> pendingUploadPartTasks = new List<Task<UploadPartResponse>>();
			SemaphoreSlim localThrottler = null;
			CancellationTokenSource internalCts = null;
			checked
			{
				try
				{
					Logger.DebugFormat("Queue up the UploadPartRequests to be executed");
					long num = 0L;
					int num2 = 1;
					while (num < _contentLength)
					{
						cancellationToken.ThrowIfCancellationRequested();
						UploadPartRequest item = ConstructUploadPartRequest(num2, num, initResponse);
						_partsToUpload.Enqueue(item);
						num += _partSize;
						num2++;
					}
					_totalNumberOfParts = _partsToUpload.Count;
					Logger.DebugFormat("Scheduling the {0} UploadPartRequests in the queue", _totalNumberOfParts);
					internalCts = CancellationTokenSource.CreateLinkedTokenSource(cancellationToken);
					int initialCount = CalculateConcurrentServiceRequests();
					localThrottler = ((AsyncThrottler == null) ? new SemaphoreSlim(initialCount) : AsyncThrottler);
					foreach (UploadPartRequest uploadRequest in _partsToUpload)
					{
						await localThrottler.WaitAsync(cancellationToken).ConfigureAwait(continueOnCapturedContext: false);
						cancellationToken.ThrowIfCancellationRequested();
						if (!internalCts.IsCancellationRequested)
						{
							Task<UploadPartResponse> item2 = UploadPartAsync(uploadRequest, internalCts, localThrottler);
							pendingUploadPartTasks.Add(item2);
							continue;
						}
						break;
					}
					Logger.DebugFormat("Waiting for upload part requests to complete. ({0})", initResponse.UploadId);
					MultipartUploadCommand multipartUploadCommand = this;
					_ = multipartUploadCommand._uploadResponses;
					multipartUploadCommand._uploadResponses = await BaseCommand.WhenAllOrFirstExceptionAsync(pendingUploadPartTasks, cancellationToken).ConfigureAwait(continueOnCapturedContext: false);
					Logger.DebugFormat("Beginning completing multipart. ({0})", initResponse.UploadId);
					CompleteMultipartUploadRequest request2 = ConstructCompleteMultipartUploadRequest(initResponse);
					await _s3Client.CompleteMultipartUploadAsync(request2, cancellationToken).ConfigureAwait(continueOnCapturedContext: false);
					Logger.DebugFormat("Done completing multipart. ({0})", initResponse.UploadId);
				}
				catch (Exception exception)
				{
					Logger.Error(exception, "Exception while uploading. ({0})", initResponse.UploadId);
					Cleanup(initResponse.UploadId, pendingUploadPartTasks);
					throw;
				}
				finally
				{
					internalCts?.Dispose();
					if (localThrottler != null && localThrottler != AsyncThrottler)
					{
						localThrottler.Dispose();
					}
					if (_fileTransporterRequest.InputStream != null && !_fileTransporterRequest.IsSetFilePath() && _fileTransporterRequest.AutoCloseStream)
					{
						_fileTransporterRequest.InputStream.Dispose();
					}
					if (Logger != null)
					{
						Logger.Flush();
					}
				}
			}
		}

		private async Task<UploadPartResponse> UploadPartAsync(UploadPartRequest uploadRequest, CancellationTokenSource internalCts, SemaphoreSlim asyncThrottler)
		{
			try
			{
				return await _s3Client.UploadPartAsync(uploadRequest, internalCts.Token).ConfigureAwait(continueOnCapturedContext: false);
			}
			catch (Exception ex)
			{
				if (!(ex is OperationCanceledException))
				{
					internalCts.Cancel();
				}
				throw;
			}
			finally
			{
				asyncThrottler.Release();
			}
		}

		private void Cleanup(string uploadId, List<Task<UploadPartResponse>> tasks)
		{
			try
			{
				Task.WaitAll(tasks.ToArray(), 5000);
			}
			catch (Exception ex)
			{
				Logger.InfoFormat("A timeout occured while waiting for all upload part request to complete as part of aborting the multipart upload : {0}", ex.Message);
			}
			AbortMultipartUpload(uploadId);
		}

		private void AbortMultipartUpload(string uploadId)
		{
			try
			{
				_s3Client.AbortMultipartUploadAsync(new AbortMultipartUploadRequest
				{
					BucketName = _fileTransporterRequest.BucketName,
					Key = _fileTransporterRequest.Key,
					UploadId = uploadId
				}).Wait();
			}
			catch (Exception ex)
			{
				Logger.InfoFormat("Error attempting to abort multipart for key {0}: {1}", _fileTransporterRequest.Key, ex.Message);
			}
		}
	}
	internal class ProgressHandler
	{
		private StreamTransferProgressArgs _lastProgressArgs;

		private EventHandler<UploadProgressArgs> _callback;

		public ProgressHandler(EventHandler<UploadProgressArgs> callback)
		{
			if (callback == null)
			{
				throw new ArgumentNullException("callback");
			}
			_callback = callback;
		}

		public void OnTransferProgress(object sender, StreamTransferProgressArgs e)
		{
			long compensationForRetry = 0L;
			if (_lastProgressArgs != null && _lastProgressArgs.TransferredBytes >= e.TransferredBytes)
			{
				compensationForRetry = _lastProgressArgs.TransferredBytes;
			}
			UploadProgressArgs e2 = new UploadProgressArgs(e.IncrementTransferred, e.TransferredBytes, e.TotalBytes, compensationForRetry, null);
			_callback(this, e2);
			_lastProgressArgs = e;
		}
	}
	internal class OpenStreamCommand : BaseCommand
	{
		private IAmazonS3 _s3Client;

		private TransferUtilityOpenStreamRequest _request;

		private Stream _responseStream;

		internal Stream ResponseStream => _responseStream;

		public override object Return => ResponseStream;

		internal OpenStreamCommand(IAmazonS3 s3Client, TransferUtilityOpenStreamRequest request)
		{
			_s3Client = s3Client;
			_request = request;
		}

		private GetObjectRequest ConstructRequest()
		{
			if (!_request.IsSetBucketName())
			{
				throw new InvalidOperationException("The bucketName Specified is null or empty!");
			}
			if (!_request.IsSetKey())
			{
				throw new InvalidOperationException("The key Specified is null or empty!");
			}
			return ConvertToGetObjectRequest(_request);
		}

		public override async Task ExecuteAsync(CancellationToken cancellationToken)
		{
			GetObjectRequest request = ConstructRequest();
			_responseStream = (await _s3Client.GetObjectAsync(request, cancellationToken).ConfigureAwait(continueOnCapturedContext: false)).ResponseStream;
		}
	}
	internal class SimpleUploadCommand : BaseCommand
	{
		private IAmazonS3 _s3Client;

		private TransferUtilityConfig _config;

		private TransferUtilityUploadRequest _fileTransporterRequest;

		public SemaphoreSlim AsyncThrottler { get; set; }

		internal SimpleUploadCommand(IAmazonS3 s3Client, TransferUtilityConfig config, TransferUtilityUploadRequest fileTransporterRequest)
		{
			_s3Client = s3Client;
			_config = config;
			_fileTransporterRequest = fileTransporterRequest;
			_ = fileTransporterRequest.FilePath;
		}

		private PutObjectRequest ConstructRequest()
		{
			PutObjectRequest putObjectRequest = new PutObjectRequest
			{
				Headers = _fileTransporterRequest.Headers,
				BucketName = _fileTransporterRequest.BucketName,
				Key = _fileTransporterRequest.Key,
				CannedACL = _fileTransporterRequest.CannedACL,
				StorageClass = _fileTransporterRequest.StorageClass,
				AutoCloseStream = _fileTransporterRequest.AutoCloseStream,
				AutoResetStreamPosition = _fileTransporterRequest.AutoResetStreamPosition,
				ServerSideEncryptionMethod = _fileTransporterRequest.ServerSideEncryptionMethod,
				ServerSideEncryptionCustomerMethod = _fileTransporterRequest.ServerSideEncryptionCustomerMethod,
				ServerSideEncryptionCustomerProvidedKey = _fileTransporterRequest.ServerSideEncryptionCustomerProvidedKey,
				ServerSideEncryptionCustomerProvidedKeyMD5 = _fileTransporterRequest.ServerSideEncryptionCustomerProvidedKeyMD5,
				ServerSideEncryptionKeyManagementServiceKeyId = _fileTransporterRequest.ServerSideEncryptionKeyManagementServiceKeyId,
				Metadata = _fileTransporterRequest.Metadata,
				TagSet = _fileTransporterRequest.TagSet
			};
			if (!string.IsNullOrEmpty(_fileTransporterRequest.ContentType))
			{
				putObjectRequest.ContentType = _fileTransporterRequest.ContentType;
			}
			putObjectRequest.FilePath = _fileTransporterRequest.FilePath;
			ProgressHandler progressHandler = new ProgressHandler(PutObjectProgressEventCallback);
			((IAmazonWebServiceRequest)putObjectRequest).StreamUploadProgressCallback = (EventHandler<StreamTransferProgressArgs>)Delegate.Combine(((IAmazonWebServiceRequest)putObjectRequest).StreamUploadProgressCallback, new EventHandler<StreamTransferProgressArgs>(progressHandler.OnTransferProgress));
			((IAmazonWebServiceRequest)putObjectRequest).AddBeforeRequestHandler((RequestEventHandler)base.RequestEventHandler);
			putObjectRequest.InputStream = _fileTransporterRequest.InputStream;
			return putObjectRequest;
		}

		private void PutObjectProgressEventCallback(object sender, UploadProgressArgs e)
		{
			UploadProgressArgs progressArgs = new UploadProgressArgs(e.IncrementTransferred, e.TransferredBytes, e.TotalBytes, e.CompensationForRetry, _fileTransporterRequest.FilePath);
			_fileTransporterRequest.OnRaiseProgressEvent(progressArgs);
		}

		public override async Task ExecuteAsync(CancellationToken cancellationToken)
		{
			_ = 1;
			try
			{
				if (AsyncThrottler != null)
				{
					await AsyncThrottler.WaitAsync(cancellationToken).ConfigureAwait(continueOnCapturedContext: false);
				}
				PutObjectRequest request = ConstructRequest();
				await _s3Client.PutObjectAsync(request, cancellationToken).ConfigureAwait(continueOnCapturedContext: false);
			}
			finally
			{
				if (AsyncThrottler != null)
				{
					AsyncThrottler.Release();
				}
			}
		}
	}
