		public static string MimeTypeFromExtension(string ext)
		{
			if (extensionToMime.ContainsKey(ext))
			{
				return extensionToMime[ext];
			}
			return "application/octet-stream";
		}

		public static string UrlEncode(string data, bool path)
		{
			return AWSSDKUtils.UrlEncode(data, path);
		}

		public static Stream MakeStreamSeekable(Stream input)
		{
			MemoryStream memoryStream = new MemoryStream();
			byte[] buffer = new byte[32768];
			int num = 0;
			using (input)
			{
				while ((num = input.Read(buffer, 0, 32768)) > 0)
				{
					memoryStream.Write(buffer, 0, num);
				}
			}
			memoryStream.Position = 0L;
			return memoryStream;
		}

		public static string GenerateChecksumForContent(string content, bool fBase64Encode)
		{
			byte[] array = CryptoUtilFactory.CryptoInstance.ComputeMD5Hash(Encoding.UTF8.GetBytes(content));
			if (fBase64Encode)
			{
				return Convert.ToBase64String(array);
			}
			return BitConverter.ToString(array).Replace("-", string.Empty);
		}

		internal static string ComputeEncodedMD5FromEncodedString(string base64EncodedString)
		{
			byte[] data = Convert.FromBase64String(base64EncodedString);
			return Convert.ToBase64String(CryptoUtilFactory.CryptoInstance.ComputeMD5Hash(data));
		}

		internal static void SetMetadataHeaders(IRequest request, MetadataCollection metadata)
		{
			foreach (string key in metadata.Keys)
			{
				request.Headers[key] = (AWSConfigsS3.EnableUnicodeEncodingForObjectMetadata ? EscapeNonAscii(metadata[key]) : metadata[key]);
			}
		}

		private static string EscapeNonAscii(string text)
		{
			StringBuilder stringBuilder = new StringBuilder("");
			for (int i = 0; i < text.Length; i++)
			{
				char c = text[i];
				stringBuilder.Append((c > '\u007f') ? Uri.EscapeDataString(c.ToString()) : c.ToString());
			}
			return stringBuilder.ToString();
		}

		internal static DateTime? ParseExpiresHeader(string rawValue, string requestId)
		{
			if (!string.IsNullOrEmpty(rawValue))
			{
				try
				{
					return S3Transforms.ToDateTime(rawValue);
				}
				catch (FormatException innerException)
				{
					throw new AmazonDateTimeUnmarshallingException(requestId, string.Empty, string.Empty, rawValue, string.Format(CultureInfo.InvariantCulture, "The value {0} cannot be converted to a DateTime instance.", new object[1] { rawValue }), innerException);
				}
			}
			return default(DateTime);
		}

		public static bool ValidateV2Bucket(string bucketName)
		{
			if (string.IsNullOrEmpty(bucketName))
			{
				throw new ArgumentNullException("bucketName", "Please specify a bucket name");
			}
			if (bucketName.StartsWith("s3.amazonaws.com", StringComparison.Ordinal))
			{
				return false;
			}
			int num = bucketName.IndexOf(".s3.amazonaws.com", StringComparison.Ordinal);
			if (num > 0)
			{
				bucketName = bucketName.Substring(0, num);
			}
			if (bucketName.Length < 3 || bucketName.Length > 63 || bucketName.StartsWith(".", StringComparison.Ordinal) || bucketName.EndsWith(".", StringComparison.Ordinal))
			{
				return false;
			}
			if (new Regex("^[0-9]+\\.[0-9]+\\.[0-9]+\\.[0-9]+$").IsMatch(bucketName))
			{
				return false;
			}
			Regex regex = new Regex("^[a-z0-9]([a-z0-9\\-]*[a-z0-9])?$");
			string[] array = bucketName.Split("\\.".ToCharArray());
			foreach (string input in array)
			{
				if (!regex.IsMatch(input))
				{
					return false;
				}
			}
			return true;
		}

		internal static void AddQueryStringParameter(StringBuilder queryString, string parameterName, string parameterValue)
		{
			AddQueryStringParameter(queryString, parameterName, parameterValue, null);
		}

		internal static void AddQueryStringParameter(StringBuilder queryString, string parameterName, string parameterValue, IDictionary<string, string> parameterMap)
		{
			if (queryString.Length > 0)
			{
				queryString.Append("&");
			}
			queryString.AppendFormat("{0}={1}", new object[2]
			{
				AWSSDKUtils.UrlEncode(parameterName, path: false),
				AWSSDKUtils.UrlEncode(parameterValue, path: false)
			});
			parameterMap?.Add(parameterName, parameterValue);
		}

		internal static string TagSetToQueryString(List<Tag> tags)
		{
			StringBuilder stringBuilder = new StringBuilder();
			foreach (Tag tag in tags)
			{
				AddQueryStringParameter(stringBuilder, tag.Key, tag.Value);
			}
			return stringBuilder.ToString();
		}

		internal static void SerializeTagToXml(XmlWriter xmlWriter, Tag tag)
		{
			xmlWriter.WriteStartElement("Tag", "");
			if (tag.IsSetKey())
			{
				xmlWriter.WriteElementString("Key", "", S3Transforms.ToXmlStringValue(tag.Key));
			}
			if (tag.IsSetValue())
			{
				xmlWriter.WriteElementString("Value", "", S3Transforms.ToXmlStringValue(tag.Value));
			}
			xmlWriter.WriteEndElement();
		}

		internal static void SerializeTagSetToXml(XmlWriter xmlWriter, List<Tag> tagset)
		{
			xmlWriter.WriteStartElement("TagSet", "");
			if (tagset != null && tagset.Count > 0)
			{
				foreach (Tag item in tagset)
				{
					SerializeTagToXml(xmlWriter, item);
				}
			}
			xmlWriter.WriteEndElement();
		}

		internal static string SerializeTaggingToXml(Tagging tagging)
		{
			StringWriter stringWriter = new StringWriter(CultureInfo.InvariantCulture);
			using (XmlWriter xmlWriter = XmlWriter.Create(stringWriter, new XmlWriterSettings
			{
				Encoding = Encoding.UTF8,
				OmitXmlDeclaration = true
			}))
			{
				xmlWriter.WriteStartElement("Tagging", "");
				SerializeTagSetToXml(xmlWriter, tagging.TagSet);
				xmlWriter.WriteEndElement();
			}
			return stringWriter.ToString();
		}

		internal static void ParseAmzRestoreHeader(string header, out bool restoreInProgress, out DateTime? restoreExpiration)
		{
			restoreExpiration = null;
			restoreInProgress = false;
			if (header == null)
			{
				return;
			}
			int num = header.IndexOf("ongoing-request", StringComparison.Ordinal);
			checked
			{
				if (num != -1)
				{
					int num2 = header.IndexOf('"', num) + 1;
					int num3 = header.IndexOf('"', num2 + 1);
					if (bool.TryParse(header.Substring(num2, num3 - num2), out var result))
					{
						restoreInProgress = result;
					}
				}
				num = header.IndexOf("expiry-date", StringComparison.Ordinal);
				if (num != -1)
				{
					int num4 = header.IndexOf('"', num) + 1;
					int num5 = header.IndexOf('"', num4 + 1);
					if (DateTime.TryParseExact(header.Substring(num4, num5 - num4), "ddd, dd MMM yyyy HH:mm:ss \\G\\M\\T", CultureInfo.InvariantCulture, DateTimeStyles.AdjustToUniversal | DateTimeStyles.AssumeUniversal, out var result2))
					{
						restoreExpiration = result2;
					}
				}
			}
		}

		internal static bool IsInstructionFile(string key)
		{
			return key.EndsWith("INSTRUCTION_SUFFIX", StringComparison.Ordinal);
		}

		public static async Task<bool> DoesS3BucketExistV2Async(IAmazonS3 s3Client, string bucketName)
		{
			try
			{
				await s3Client.GetACLAsync(bucketName).ConfigureAwait(continueOnCapturedContext: false);
			}
			catch (AmazonS3Exception ex)
			{
				switch (ex.ErrorCode)
				{
				case "AccessDenied":
				case "PermanentRedirect":
					return true;
				case "NoSuchBucket":
					return false;
				default:
					throw;
				}
			}
			return true;
		}

		[Obsolete("This method is deprecated: its behavior is inconsistent and always uses HTTP. Please use DoesS3BucketExistV2Async instead.")]
		public static async Task<bool> DoesS3BucketExistAsync(IAmazonS3 s3Client, string bucketName)
		{
			if (s3Client == null)
			{
				throw new ArgumentNullException("s3Client", "The s3Client cannot be null!");
			}
			if (string.IsNullOrEmpty(bucketName))
			{
				throw new ArgumentNullException("bucketName", "The bucketName cannot be null or the empty string!");
			}
			GetPreSignedUrlRequest request = new GetPreSignedUrlRequest
			{
				BucketName = bucketName,
				Expires = s3Client.Config.CorrectedUtcNow.ToLocalTime().AddDays(1.0),
				Verb = HttpVerb.HEAD,
				Protocol = Protocol.HTTP
			};
			HttpWebRequest httpWebRequest = WebRequest.Create(new Uri(s3Client.GetPreSignedURL(request))) as HttpWebRequest;
			httpWebRequest.Method = "HEAD";
			if (s3Client is AmazonS3Client amazonS3Client)
			{
				amazonS3Client.ConfigureProxy(httpWebRequest);
			}
			try
			{
				IAsyncResult asyncResult = httpWebRequest.BeginGetResponse(null, null);
				using (httpWebRequest.EndGetResponse(asyncResult) as HttpWebResponse)
				{
					return true;
				}
			}
			catch (WebException ex)
			{
				using HttpWebResponse httpWebResponse = ex.Response as HttpWebResponse;
				if (httpWebResponse != null)
				{
					HttpStatusCode statusCode = httpWebResponse.StatusCode;
					return statusCode != HttpStatusCode.NotFound && statusCode != HttpStatusCode.BadRequest;
				}
				return false;
			}
		}
	}
	public static class BucketRegionDetector
	{
		private const int BucketRegionCacheMaxEntries = 300;

		private const string AuthorizationHeaderMalformedErrorCode = "AuthorizationHeaderMalformed";

		public static LruCache<string, RegionEndpoint> BucketRegionCache { get; private set; }

		static BucketRegionDetector()
		{
			BucketRegionCache = new LruCache<string, RegionEndpoint>(300);
		}

		internal static string GetCorrectRegion(AmazonS3Uri requestedBucketUri, HttpStatusCode headBucketStatusCode, string xAmzBucketRegionHeaderValue)
		{
			if (xAmzBucketRegionHeaderValue != null && headBucketStatusCode == HttpStatusCode.BadRequest)
			{
				return CheckRegionAndUpdateCache(requestedBucketUri, xAmzBucketRegionHeaderValue);
			}
			return null;
		}

		private static string GetCorrectRegion(AmazonS3Uri requestedBucketUri, AmazonServiceException serviceException)
		{
			string text = null;
			string text2 = null;
			if (serviceException is AmazonS3Exception ex)
			{
				if (string.Equals(ex.ErrorCode, "AuthorizationHeaderMalformed", StringComparison.Ordinal))
				{
					text = CheckRegionAndUpdateCache(requestedBucketUri, ex.Region);
				}
				if (text == null && ex.InnerException is HttpErrorResponseException { Response: not null } ex2 && ex2.Response.IsHeaderPresent("x-amz-bucket-region"))
				{
					text2 = CheckRegionAndUpdateCache(requestedBucketUri, ex2.Response.GetHeaderValue("x-amz-bucket-region"));
				}
			}
			return text ?? text2;
		}

		private static string CheckRegionAndUpdateCache(AmazonS3Uri requestedBucketUri, string actualRegion)
		{
			string a = ((requestedBucketUri.Region == null) ? null : requestedBucketUri.Region.SystemName);
			if (actualRegion != null && !string.Equals(a, actualRegion, StringComparison.Ordinal))
			{
				BucketRegionCache.AddOrUpdate(requestedBucketUri.Bucket, RegionEndpoint.GetBySystemName(actualRegion));
				return actualRegion;
			}
			return null;
		}

		private static string GetHeadBucketPreSignedUrl(string bucketName, ImmutableCredentials credentials)
		{
			using AmazonS3Client amazonS3Client = GetUsEast1ClientFromCredentials(credentials);
			GetPreSignedUrlRequest request = new GetPreSignedUrlRequest
			{
				BucketName = bucketName,
				Expires = amazonS3Client.Config.CorrectedUtcNow.ToLocalTime().AddDays(1.0),
				Verb = HttpVerb.HEAD,
				Protocol = Protocol.HTTP
			};
			return amazonS3Client.GetPreSignedURLInternal(request, useSigV2Fallback: false);
		}

		private static AmazonS3Client GetUsEast1ClientFromCredentials(ImmutableCredentials credentials)
		{
			if (credentials.UseToken)
			{
				return new AmazonS3Client(credentials.AccessKey, credentials.SecretKey, credentials.Token, RegionEndpoint.USEast1);
			}
			return new AmazonS3Client(credentials.AccessKey, credentials.SecretKey, RegionEndpoint.USEast1);
		}

		internal static async Task<string> DetectMismatchWithHeadBucketFallbackAsync(AmazonS3Uri requestedBucketUri, AmazonServiceException serviceException, ImmutableCredentials credentials)
		{
			string text = GetCorrectRegion(requestedBucketUri, serviceException);
			if (text == null)
			{
				text = CheckRegionAndUpdateCache(requestedBucketUri, await GetBucketRegionNoPipelineAsync(requestedBucketUri.Bucket, credentials));
			}
			return text;
		}

		private static async Task<string> GetBucketRegionNoPipelineAsync(string bucketName, ImmutableCredentials credentials)
		{
			string headBucketPreSignedUrl = GetHeadBucketPreSignedUrl(bucketName, credentials);
			using AmazonS3Client s3Client = GetUsEast1ClientFromCredentials(credentials);
			return (await AmazonS3HttpUtil.GetHeadAsync(s3Client, s3Client.Config, headBucketPreSignedUrl, "x-amz-bucket-region").ConfigureAwait(continueOnCapturedContext: false)).HeaderValue;
		}
	}
