	public class Expiration
	{
		private DateTime expiryDate;

		private DateTime expiryDateUtc;

		private string ruleId;

		private static Regex expiryRegex = new Regex("expiry-date=\"(.+?)\"");

		private static Regex ruleRegex = new Regex("rule-id=\"(.+?)\"");

		[Obsolete("This property returns a DateTime of kind Unspecified. Use ExpiryDateUtc instead.", false)]
		public DateTime ExpiryDate
		{
			get
			{
				return expiryDate;
			}
			set
			{
				expiryDate = value;
			}
		}

		public DateTime ExpiryDateUtc
		{
			get
			{
				return expiryDateUtc;
			}
			set
			{
				expiryDateUtc = value;
			}
		}

		public string RuleId
		{
			get
			{
				return ruleId;
			}
			set
			{
				ruleId = value;
			}
		}

		public Expiration()
		{
			expiryDate = DateTime.MinValue;
			ruleId = string.Empty;
		}

		internal Expiration(string headerValue)
		{
			if (string.IsNullOrEmpty(headerValue))
			{
				throw new ArgumentNullException("headerValue");
			}
			Match match = expiryRegex.Match(headerValue);
			if (!match.Success || !match.Groups[1].Success)
			{
				throw new InvalidOperationException("No Expiry Date match");
			}
			string value = match.Groups[1].Value;
			expiryDateUtc = DateTime.ParseExact(value, "ddd, dd MMM yyyy HH:mm:ss \\G\\M\\T", CultureInfo.InvariantCulture, DateTimeStyles.AdjustToUniversal | DateTimeStyles.AssumeUniversal);
			expiryDate = new DateTime(expiryDateUtc.Ticks, DateTimeKind.Unspecified);
			Match match2 = ruleRegex.Match(headerValue);
			if (!match2.Success || !match2.Groups[1].Success)
			{
				throw new InvalidOperationException("No Rule Id match");
			}
			string value2 = match2.Groups[1].Value;
			ruleId = UrlDecode(value2);
		}

		private static string UrlDecode(string url)
		{
			return Uri.UnescapeDataString(url).Replace("+", " ");
		}
	}
