		private void ValidateWrittenStreamSize(long bytesWritten)
		{
			if (bytesWritten != base.ContentLength)
			{
				if (!base.ResponseMetadata.Metadata.TryGetValue("x-amz-id-2", out var value))
				{
					value = string.Empty;
				}
				if (!base.ResponseMetadata.Metadata.TryGetValue("X-Amz-Cf-Id", out var value2))
				{
					value2 = string.Empty;
				}
				string text = null;
				text = ((!string.IsNullOrEmpty(value2)) ? string.Format(CultureInfo.InvariantCulture, "The total bytes read {0} from response stream is not equal to the Content-Length {1} for the object {2} in bucket {3}. Request ID = {4} , AmzId2 = {5} , AmzCfId = {6}.", bytesWritten, base.ContentLength, Key, BucketName, base.ResponseMetadata.RequestId, value, value2) : string.Format(CultureInfo.InvariantCulture, "The total bytes read {0} from response stream is not equal to the Content-Length {1} for the object {2} in bucket {3}. Request ID = {4} , AmzId2 = {5}.", bytesWritten, base.ContentLength, Key, BucketName, base.ResponseMetadata.RequestId, value));
				throw new StreamSizeMismatchException(text, base.ContentLength, bytesWritten, base.ResponseMetadata.RequestId, value, value2);
			}
		}

		public async Task WriteResponseStreamToFileAsync(string filePath, bool append, CancellationToken cancellationToken = default(CancellationToken))
		{
			await CreateDirectory(filePath).ConfigureAwait(continueOnCapturedContext: false);
			Stream downloadStream = await CreateDownloadStream(filePath, append).ConfigureAwait(continueOnCapturedContext: false);
			checked
			{
				using (downloadStream)
				{
					long current = 0L;
					byte[] buffer = new byte[8192];
					long totalIncrementTransferred = 0L;
					while (true)
					{
						int num;
						int bytesRead = (num = await ResponseStream.ReadAsync(buffer, 0, buffer.Length, cancellationToken).ConfigureAwait(continueOnCapturedContext: false));
						if (num <= 0)
						{
							break;
						}
						cancellationToken.ThrowIfCancellationRequested();
						await downloadStream.WriteAsync(buffer, 0, bytesRead, cancellationToken).ConfigureAwait(continueOnCapturedContext: false);
						current += bytesRead;
						totalIncrementTransferred += bytesRead;
						if (totalIncrementTransferred >= 102400)
						{
							OnRaiseProgressEvent(filePath, totalIncrementTransferred, current, ContentLength, completed: false);
							totalIncrementTransferred = 0L;
						}
					}
					ValidateWrittenStreamSize(current);
					OnRaiseProgressEvent(filePath, totalIncrementTransferred, current, ContentLength, completed: true);
				}
			}
		}

		private static async Task<Stream> CreateDownloadStream(string filePath, bool append)
		{
			await FileSystem.Current.LocalStorage.CheckExistsAsync(filePath).ConfigureAwait(continueOnCapturedContext: false);
			Stream stream = await (await FileSystem.Current.LocalStorage.CreateFileAsync(filePath, CreationCollisionOption.OpenIfExists).ConfigureAwait(continueOnCapturedContext: false)).OpenAsync(PCLStorage.FileAccess.ReadAndWrite).ConfigureAwait(continueOnCapturedContext: false);
			if (append)
			{
				stream.Seek(0L, SeekOrigin.End);
			}
			return stream;
		}

		private static async Task CreateDirectory(string filePath)
		{
			string directoryName = Path.GetDirectoryName(filePath);
			await FileSystem.Current.LocalStorage.CreateFolderAsync(directoryName, CreationCollisionOption.OpenIfExists).ConfigureAwait(continueOnCapturedContext: false);
		}
	}
